final:
module RefModule(
    input wire clk,
    input wire load,
    input wire [7:0] data,
    output wire q
);

reg [7:0] register;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (load)
        register <= data;
    else
        register <= register >> 1;
end

assign q = register[0];

endmodule
